46	public class MarkdownGenerator implements Closeable {
47	
48	    protected static final Logger LOGGER = Logger.getLogger(MarkdownGenerator.class.getCanonicalName());
49	    protected final java.io.Writer markdownWriter;
50	    protected final String markdownFileName;
51	    protected int tableNesting = 0;
52	    protected boolean isImageSupported;
53	    protected String markdownPageSeparator;
54	    protected boolean embedImages = false;
55	    protected String imageFormat = Config.IMAGE_FORMAT_PNG;
56	    protected boolean includeHeaderFooter = false;
57	
58	    MarkdownGenerator(File inputPdf, Config config) throws IOException {
59	        String cutPdfFileName = inputPdf.getName();
60	        this.markdownFileName = config.getOutputFolder() + File.separator + cutPdfFileName.substring(0, cutPdfFileName.length() - 3) + "md";
61	        this.markdownWriter = new FileWriter(markdownFileName, StandardCharsets.UTF_8);
62	        this.isImageSupported = !config.isImageOutputOff() && config.isGenerateMarkdown();
63	        this.markdownPageSeparator = config.getMarkdownPageSeparator();
64	        this.embedImages = config.isEmbedImages();
65	        this.imageFormat = config.getImageFormat();
66	        this.includeHeaderFooter = config.isIncludeHeaderFooter();
67	    }
68	
69	    /**
70	     * Creates a MarkdownGenerator that writes to an arbitrary Writer (e.g., stdout).
71	     */
72	    public MarkdownGenerator(java.io.Writer writer, Config config) {
73	        this.markdownFileName = null;
74	        this.markdownWriter = writer;
75	        this.isImageSupported = false;
76	        this.markdownPageSeparator = config.getMarkdownPageSeparator();
77	        this.embedImages = false;
78	        this.imageFormat = config.getImageFormat();
79	        this.includeHeaderFooter = config.isIncludeHeaderFooter();
80	    }
81	
82	    public void writeToMarkdown(List<List<IObject>> contents) {
83	        try {
84	            for (int pageNumber = 0; pageNumber < StaticContainers.getDocument().getNumberOfPages(); pageNumber++) {
85	                writePageSeparator(pageNumber);
86	                for (IObject content : contents.get(pageNumber)) {
87	                    if (!isSupportedContent(content)) {
88	                        continue;
89	                    }
90	                    this.write(content);
91	                    writeContentsSeparator();
92	                }
93	            }
94	
95	            LOGGER.log(Level.INFO, "Created {0}", markdownFileName);
96	        } catch (Exception e) {
97	            LOGGER.log(Level.WARNING, "Unable to create markdown output: " + e.getMessage());
98	        }
99	    }
100	
101	    protected void writePageSeparator(int pageNumber) throws IOException {
102	        if (!markdownPageSeparator.isEmpty()) {
103	            markdownWriter.write(markdownPageSeparator.contains(Config.PAGE_NUMBER_STRING)
104	                ? markdownPageSeparator.replace(Config.PAGE_NUMBER_STRING, String.valueOf(pageNumber + 1))
105	                : markdownPageSeparator);
106	            writeContentsSeparator();
107	        }
108	    }
109	
110	    protected boolean isSupportedContent(IObject content) {
111	        if (content instanceof SemanticHeaderOrFooter) {
112	            return includeHeaderFooter;
113	        }
114	        return content instanceof SemanticTextNode || // Heading, Paragraph etc...
115	            content instanceof SemanticFormula ||
116	            content instanceof SemanticPicture ||
117	            content instanceof TableBorder ||
118	            content instanceof PDFList ||
119	            (content instanceof ImageChunk && isImageSupported);
120	    }
121	
122	    protected void writeContentsSeparator() throws IOException {
123	        writeLineBreak();
124	        writeLineBreak();
125	    }
126	
127	    protected void write(IObject object) throws IOException {
128	        if (object instanceof SemanticHeaderOrFooter) {
129	            writeHeaderOrFooter((SemanticHeaderOrFooter) object);
130	        } else if (object instanceof SemanticPicture) {
131	            writePicture((SemanticPicture) object);
132	        } else if (object instanceof ImageChunk) {
133	            writeImage((ImageChunk) object);
134	        } else if (object instanceof SemanticFormula) {
135	            writeFormula((SemanticFormula) object);
136	        } else if (object instanceof SemanticHeading) {
137	            writeHeading((SemanticHeading) object);
138	        } else if (object instanceof SemanticParagraph) {
139	            writeParagraph((SemanticParagraph) object);
140	        } else if (object instanceof SemanticTextNode) {
141	            writeSemanticTextNode((SemanticTextNode) object);
142	        } else if (object instanceof TableBorder) {
143	            writeTable((TableBorder) object);
144	        } else if (object instanceof PDFList) {
145	            writeList((PDFList) object);
146	        }
147	    }
148	
149	    protected void writeImage(ImageChunk image) {
150	        try {
151	            String absolutePath = String.format(MarkdownSyntax.IMAGE_FILE_NAME_FORMAT, StaticLayoutContainers.getImagesDirectory(), File.separator, image.getIndex(), imageFormat);
152	            String relativePath = String.format(MarkdownSyntax.IMAGE_FILE_NAME_FORMAT, StaticLayoutContainers.getImagesDirectoryName(), "/", image.getIndex(), imageFormat);
153	
154	            if (ImagesUtils.isImageFileExists(absolutePath)) {
155	                String imageSource;
156	                if (embedImages) {
157	                    File imageFile = new File(absolutePath);
158	                    imageSource = Base64ImageUtils.toDataUri(imageFile, imageFormat);
159	                    if (imageSource == null) {
160	                        LOGGER.log(Level.WARNING, "Failed to convert image to Base64: {0}", absolutePath);
161	                    }
162	                } else {
163	                    imageSource = relativePath;
164	                }
165	                if (imageSource != null) {
166	                    String imageString = String.format(MarkdownSyntax.IMAGE_FORMAT, "image " + image.getIndex(), imageSource);
167	                    markdownWriter.write(getCorrectMarkdownString(imageString));
168	                }
169	            }
170	        } catch (IOException e) {
171	            LOGGER.log(Level.WARNING, "Unable to write image for markdown output: " + e.getMessage());
172	        }
173	    }
174	
175	    /**
176	     * Writes a SemanticPicture with its description as alt text.
177	     *
178	     * @param picture The picture to write
179	     */
180	    protected void writePicture(SemanticPicture picture) {
181	        try {
182	            String absolutePath = String.format(MarkdownSyntax.IMAGE_FILE_NAME_FORMAT, StaticLayoutContainers.getImagesDirectory(), File.separator, picture.getPictureIndex(), imageFormat);
183	            String relativePath = String.format(MarkdownSyntax.IMAGE_FILE_NAME_FORMAT, StaticLayoutContainers.getImagesDirectoryName(), "/", picture.getPictureIndex(), imageFormat);
184	
185	            if (ImagesUtils.isImageFileExists(absolutePath)) {
186	                String imageSource;
187	                if (embedImages) {
188	                    File imageFile = new File(absolutePath);
189	                    imageSource = Base64ImageUtils.toDataUri(imageFile, imageFormat);
190	                    if (imageSource == null) {
191	                        LOGGER.log(Level.WARNING, "Failed to convert image to Base64: {0}", absolutePath);
192	                    }
193	                } else {
194	                    imageSource = relativePath;
195	                }
196	                if (imageSource != null) {
197	                    String altText = picture.hasDescription()
198	                            ? picture.sanitizeDescription()
199	                            : "image " + picture.getPictureIndex();
200	                    String imageString = String.format(MarkdownSyntax.IMAGE_FORMAT, altText, imageSource);
201	                    markdownWriter.write(getCorrectMarkdownString(imageString));
202	                }
203	            }
204	        } catch (IOException e) {
205	            LOGGER.log(Level.WARNING, "Unable to write picture for markdown output: " + e.getMessage());
206	        }
207	    }
208	
209	    /**
210	     * Writes a formula in LaTeX format wrapped in $$ delimiters.
211	     *
212	     * @param formula The formula to write
213	     */
214	    protected void writeFormula(SemanticFormula formula) throws IOException {
215	        markdownWriter.write(MarkdownSyntax.MATH_BLOCK_START);
216	        markdownWriter.write(MarkdownSyntax.LINE_BREAK);
217	        markdownWriter.write(formula.getLatex());
218	        markdownWriter.write(MarkdownSyntax.LINE_BREAK);
219	        markdownWriter.write(MarkdownSyntax.MATH_BLOCK_END);
220	    }
221	
222	    protected void writeHeaderOrFooter(SemanticHeaderOrFooter headerOrFooter) throws IOException {
223	        for (IObject content : headerOrFooter.getContents()) {
224	            if (isSupportedContent(content)) {
225	                write(content);
226	                writeContentsSeparator();
227	            }
228	        }
229	    }
230	
231	    protected void writeList(PDFList list) throws IOException {
232	        for (ListItem item : list.getListItems()) {
233	            if (!isInsideTable()) {
234	                markdownWriter.write(MarkdownSyntax.LIST_ITEM);
235	                markdownWriter.write(MarkdownSyntax.SPACE);
236	            }
237	            markdownWriter.write(getCorrectMarkdownString(item.toString()));
238	            writeLineBreak();
239	
240	            List<IObject> itemContents = item.getContents();
241	            if (!itemContents.isEmpty()) {
242	                writeLineBreak();
243	                writeContents(itemContents, false);
244	            }
245	        }
246	    }
247	
248	    protected void writeSemanticTextNode(SemanticTextNode textNode) throws IOException {
249	        String value = textNode.getValue();
250	        if (StaticContainers.isKeepLineBreaks()) {
251	            if (textNode instanceof SemanticHeading) {
252	                value = value.replace(MarkdownSyntax.LINE_BREAK, MarkdownSyntax.SPACE);
253	            } else if (isInsideTable()) {
254	                value = value.replace(MarkdownSyntax.LINE_BREAK, getLineBreak());
255	            }
256	        } else if (isInsideTable()) {
257	            // Always replace line breaks with space in table cells for proper markdown table formatting
258	            value = value.replace(MarkdownSyntax.LINE_BREAK, MarkdownSyntax.SPACE);
259	        }
260	
261	        markdownWriter.write(getCorrectMarkdownString(value));
262	    }
263	
264	    protected void writeTable(TableBorder table) throws IOException {
265	        enterTable();
266	        for (int rowNumber = 0; rowNumber < table.getNumberOfRows(); rowNumber++) {
267	            TableBorderRow row = table.getRow(rowNumber);
268	            markdownWriter.write(MarkdownSyntax.TABLE_COLUMN_SEPARATOR);
