39	        for (int rowNumber = 0; rowNumber < table.getNumberOfRows(); rowNumber++) {
40	            TableBorderRow row = table.getRow(rowNumber);
41	            markdownWriter.write(MarkdownSyntax.INDENT);
42	            markdownWriter.write(MarkdownSyntax.HTML_TABLE_ROW_TAG);
43	            markdownWriter.write(MarkdownSyntax.LINE_BREAK);
44	            for (int colNumber = 0; colNumber < table.getNumberOfColumns(); colNumber++) {
45	                TableBorderCell cell = row.getCell(colNumber);
46	                if (cell.getRowNumber() == rowNumber && cell.getColNumber() == colNumber) {
47	                    boolean isHeader = rowNumber == 0;
48	                    writeCellTagBegin(cell, isHeader);
49	
50	                    List<IObject> cellContents = cell.getContents();
51	                    writeContents(cellContents, true);
52	
53	                    writeCellTagEnd(isHeader);
54	                    markdownWriter.write(MarkdownSyntax.LINE_BREAK);
55	                }
56	            }
57	
58	            markdownWriter.write(MarkdownSyntax.INDENT);
59	            markdownWriter.write(MarkdownSyntax.HTML_TABLE_ROW_CLOSE_TAG);
60	            markdownWriter.write(MarkdownSyntax.LINE_BREAK);
61	        }
62	
63	        markdownWriter.write(MarkdownSyntax.HTML_TABLE_CLOSE_TAG);
64	        markdownWriter.write(MarkdownSyntax.LINE_BREAK);
65	        leaveTable();
66	    }
67	
68	    private void writeCellTagBegin(TableBorderCell cell, boolean isHeader) throws IOException {
69	        markdownWriter.write(MarkdownSyntax.INDENT);
70	        markdownWriter.write(MarkdownSyntax.INDENT);
71	        String tag = isHeader ? "<th" : "<td";
72	        StringBuilder cellTag = new StringBuilder(tag);
73	        int colSpan = cell.getColSpan();
74	        if (colSpan != 1) {
75	            cellTag.append(" colspan=\"").append(colSpan).append("\"");
76	        }
77	
78	        int rowSpan = cell.getRowSpan();
79	        if (rowSpan != 1) {
80	            cellTag.append(" rowspan=\"").append(rowSpan).append("\"");
81	        }
82	        cellTag.append(">");
83	        markdownWriter.write(getCorrectMarkdownString(cellTag.toString()));
84	    }
85	
86	    private void writeCellTagEnd(boolean isHeader) throws IOException {
87	        if (isHeader) {
88	            markdownWriter.write(MarkdownSyntax.HTML_TABLE_HEADER_CLOSE_TAG);
89	        } else {
90	            markdownWriter.write(MarkdownSyntax.HTML_TABLE_CELL_CLOSE_TAG);
91	        }
92	    }
93	}
